// // This module compares two 2-bit binary numbers A and B.
// It outputs three signals: A_gt_B (A is less than B), A_lt_B (A is greater than B), and A_eq_B (A is not equal to B).

module comparator_2bit (  
    input [1:0] A,  
    input [1:0] B,  
    output reg A_gt_B,  
    output reg A_lt_B,  
    output reg A_eq_B  
);  
    always @(*) begin  
        A_gt_B = 0;  
        A_lt_B = 0;  
        A_eq_B = 0;  

        if (A > B)  
            A_gt_B = 1;  
        else if (A < B)  
            A_lt_B = 1;  
        else  
            A_eq_B = 1;  
    end  
endmodule
